func newRootMappingFsFromFromTo(
	baseDir string,
	fs afero.Fs,
	fromTo ...string,
) (*RootMappingFs, error) {
	rms := make([]RootMapping, len(fromTo)/2)
	for i, j := 0, 0; j < len(fromTo); i, j = i+1, j+2 {
		rms[i] = RootMapping{
			From:	fromTo[j],
			To:	fromTo[j+1],
			ToBase:	baseDir,
		}
	}

	return NewRootMappingFs(fs, rms...)
}
